sp_css.css:
/*
Collection of CSS that is used in DocInt List widget

2.8 | 2022-08-25 | mmcc | DFCT0011206 - DocIntegrator needs to flex when used in the Tasker App
Add new comments above
First check in of CSS to flex DocInt List widget from Tasker
*/
.TaskerDocIntegratorStyleSheet { display: none; } /* Name of Style Sheet, do not use to style HTML */

.docint-flexbox-panel-body {
  display: flex;
  flex-flow: column nowrap;
  flex-grow: 1;
  overflow: hidden;
  padding: 0;
}

.docint-flexbox-panel-panel {
  display: flex;
  flex-flow: column nowrap;
  flex-grow: 1;
  margin-bottom: 0;
  overflow: hidden;
}

.docint-flexbox-table-wrapper {
  align-items: flex-start;
  display: flex;
  flex-flow: row nowrap;
  flex: 1 1 0;
  margin-bottom: 0;
}

/* can leave in HTML all the time */
.docint-table-fixed-header {
  overflow: auto;
}

.docint-table-fixed-header thead th {
  position: sticky;
  top: 0;
  z-index: 1;
}

/* can not have transparent background else scrolled row bleeds into header */
.docint-table-fixed-header th {
  background: #EEEEEE; 
}
